  placeholder: string,
  className: string,
  dir?: 'rtl',
): Html => {
  const h = html<Message>()
  const { onDataTableMessage } = controller

  return Input.view<Message>({
    value: state.filters[columnId] ?? '',
    placeholder,
    className,
    ...(dir === undefined ? {} : { dir }),
